function createTableFromArray(data, containerId = 'myContainer', tableId = 'myTable') {
    let existedTables = document.querySelectorAll('#' + tableId)
    if (existedTables.length > 0){
        existedTables.forEach(table => table.remove())
    }
    let container = document.querySelector('#' + containerId)
    // Check if data is empty
    if (!data || data.length === 0) {
        console.error('Data array is empty or undefined');
        return;
    }

    // Create table element
    const table = document.createElement('table');
    table.id = tableId;
    table.setAttribute('border', '1'); // Add border for visibility
    
    // Create table header from first row
    const thead = document.createElement('thead');
    const headerRow = document.createElement('tr');
    
    data[0].forEach(headerText => {
        const th = document.createElement('th');
        th.textContent = headerText;
        headerRow.appendChild(th);
    });
    
    thead.appendChild(headerRow);
    table.appendChild(thead);
    
    // Create table body from remaining rows
    const tbody = document.createElement('tbody');
    
    for (let i = 1; i < data.length; i++) {
        const row = document.createElement('tr');
        
        data[i].forEach(cellData => {
            const td = document.createElement('td');
            td.textContent = cellData;
            row.appendChild(td);
        });
        
        tbody.appendChild(row);
    }
    
    table.appendChild(tbody);
    
    // Add table to document body (or you can return the table element)
    container.innerHTML = ''
    container.appendChild(table);
    
    // Alternatively, return the table element if you want to place it elsewhere
    // return table;
}

