function waitForElementInParentIframeAndAddClickListener(elementIdorClass, myFunction) {
 /**
 • Ожидает появления элемента с указанным ID или классом в документе родительского iframe и добавляет к нему обработчик клика.
 • Этот обработчик выполняет предоставленную функцию, а затем перезапускает процесс ожидания после клика.  Это полезно в ситуациях, когда
 • элемент может быть динамически перерисован или заменен в родительском iframe.
 *
 • @param {string} elementIdorClass - CSS селектор (ID или класс) для идентификации элемента в родительском iframe.
 •                                    Например: '#myButton' или '.myClass'.
 • @param {function} myFunction - Функция, которую нужно выполнить при клике на элемент. Эта функция не должна принимать параметры.
 *
 • @remarks
 • - Функция корректно обрабатывает проблемы с межсайтовым доступом к родительскому iframe, отлавливая ошибки и записывая предупреждения в консоль.
 •   Если межсайтовый доступ запрещен, функция останавливается и не продолжает работу.
 • - Обработчик клика разработан с возможностью перезапуска. После события клика он удаляет существующий обработчик, чтобы предотвратить дублирование выполнения,
 •   а затем перезапускает функцию `waitForElementInParentIframeAndAddClickListener` после тайм-аута. Это гарантирует, что если элемент
 •   будет удален и повторно добавлен в DOM, обработчик клика будет переназначен.  `setTimeout(..., 0)` используется, чтобы избежать ошибок переполнения стека.
 • - Использует MutationObserver для отслеживания изменений в документе родительского iframe и обнаружения добавления целевого элемента в DOM.
 • - Функция предполагает, что `window.parent` ссылается на валидный iframe и его документ доступен.
 • - Ошибки в процессе наблюдения, потенциально связанные с межсайтовыми проблемами, отлавливаются и записываются в консоль.
 */
    
    
    let element = null;
    try {
        element = window.parent.document.querySelector(elementIdorClass);
    } catch (e) {
        console.warn("Access to parent iframe denied:", e);
        return; // Stop if cross-origin access is denied
    }

    if (element) {
        const clickHandler = () => {
            myFunction();  // Execute the provided function first

            // Remove the existing click listener to avoid duplicates
            element.removeEventListener('click', clickHandler);

            // Restart the waitForElement... function
            setTimeout(() => {
                waitForElementInParentIframeAndAddClickListener(elementIdorClass, myFunction); // restart after timeout
            }, 0); // Use setTimeout to avoid stack overflow
        };

        element.addEventListener('click', clickHandler);
        console.log(`Element with '${elementIdorClass}' already exists in parent iframe and click listener added (restartable).`);
        return;
    }

    let observer = new MutationObserver(function(mutations) {
        let element = null;
        try {
            element = window.parent.document.querySelector(elementIdorClass);
        } catch (e) {
            console.warn("Access to parent iframe denied:", e);
            observer.disconnect();
            return;
        }

        if (element) {
            observer.disconnect();

            const clickHandler = () => {
                myFunction();  // Execute the provided function first

                // Remove the existing click listener to avoid duplicates
                element.removeEventListener('click', clickHandler);

                // Restart the waitForElement... function
                setTimeout(() => {
                    waitForElementInParentIframeAndAddClickListener(elementIdorClass, myFunction); // restart after timeout
                }, 0); // Use setTimeout to avoid stack overflow
            };

            element.addEventListener('click', clickHandler);
            console.log(`Element with '${elementIdorClass}' found in parent iframe and click listener added (restartable).`);
        }
    });

    try {
        observer.observe(window.parent.document.documentElement, {
            childList: true,
            subtree: true,
        });
    } catch (e) {
        console.error("Error observing parent document.  Cross-origin issue?", e);
        observer.disconnect();
    }
}

function minimizeBIMenu(){
    console.log('-----------------')
    console.log('BI Menu minimized');
    // Добавляем стили для таблицы
    ['exports', 'edit-dashboard', 'maximize-dashboard'].forEach(id => {
        const div = getElementFromParent('#' + id);
        if (div) {
            removeTextFromDiv(div);
        }    
    })
    
    const inputContainer = getElementFromParent('.input-container');
    if (inputContainer){
        inputContainer.style.display = 'none'
    }
    
    const ribbonContainer = getElementFromParent('.ribbon-container.ng-trigger');
    if (ribbonContainer){
        ribbonContainer.style.flexDirection = 'row-reverse'
    }
}




function getElementFromParent(selector) {
    try {
        const parentElement = window.parent.document.querySelector(selector);
        return parentElement;
    } catch (error) {
        console.error("Could not access parent element due to cross-origin restriction:", error);
        return null;
    }
}

function removeTextFromDiv(element) {
    if (!element) {
        console.error('Parent div not found');
        return;
    }

    const children = element.childNodes;
    for (let i = 0; i < children.length; i++) {
        const child = children[i];
        if (child.nodeType === Node.TEXT_NODE) {
            if (child.textContent.trim().length > 0){
                element.removeChild(child);
               i--;
            }
        }
    }
}

