let willBeSelectedValues = []
createWidget()

visApi().onSelectedValuesChangedListener({guid: w.general.renderTo + '-' + filter.id + '-selectedValuesChanged', widgetGuid: filter.id }, function (info) {
    selectedValues = info.selectedValues.map(x => x[0])
