function addDiv(parent, startDate, endDate) {
	let div = document.createElement('div')
	div.setAttribute('start-date', startDate)
	div.setAttribute('end-date', endDate)
	div.innerHTML = renamePeriod(startDate, periodType)
	parent.appendChild(div)
}

function setDisplayStyle() {
	periodType = visApi().getSelectedValues(settings.periodTypeFilterId)[0][0].split('. ')[1]
	datePicker.querySelectorAll('div.period-block').forEach(div => {
		div.classList.remove('hidden')
		if (div.getAttribute('period-type') !== periodType) {
			div.classList.add('hidden')
		}
	})
}

function renamePeriod(periodName, periodType) {
	const year = periodName.slice(0, 4)
	let result = ''
	
	switch (periodType) {
	    case 'День':
	        result =
				`<div class='date-picker-first-row'>${year}</div><div class='date-picker-second-row' style="font-size: 12px">${periodName.slice(5,10)}</div>`
			break;
		case 'Месяц':
			let monthNumber = periodName.slice(-2)
			if (monthNumber[0] === '0') {
				monthNumber = monthNumber[1]
			}
			result =
				`<div class='date-picker-first-row'>${year}</div><div class='date-picker-second-row'>${settings.months[new Date(periodName).getMonth()].slice(0,3)}</div>`
			break;
			
		case 'Квартал':
			result =
				`<div class='date-picker-first-row'>${periodName.slice(0,4)}</div><div class='date-picker-second-row'>Q${Math.floor(new Date(periodName).getMonth() / 3 + 1)}</div>`
			break;
			
		case 'Полугодие':
			result =
				`<div class='date-picker-first-row'>${periodName.slice(0,4)}</div><div class='date-picker-second-row'>H${Math.floor(new Date(periodName).getMonth() / 6 + 1)}</div>`
			break;
			
		case 'Год':
			result = `<div class='date-picker-single-row'>${periodName.slice(0,4)}</div>`
			break;
		default:
			result = 'Не выбран тип периода'
	}
	
	return result
}

function handleDivSelection(containerDiv) {
	let startDiv = null;
	let isSelecting = false;
	let lastSelectedDivs = []; // Store last selected divs
	let startDate;
	let endDate;
	let startElement;
	let endElement;
	
	function getInnerDivs(container) {
		return Array.from(container.querySelectorAll(':scope > div'));
	}
	
	function clearSelection(container) {
		getInnerDivs(container)
			.forEach(div => {
				div.classList.remove('selected-period');
				div.style.background = '';
				div.style.color = '';
			});
	}
	
	function getClosestInnerDiv(x, y, container) {
		const innerDivs = getInnerDivs(container);
		let closestDiv = null;
		let minDistance = Infinity;
		
		innerDivs.forEach(div => {
			const rect = div.getBoundingClientRect();
			const centerX = rect.left + rect.width / 2;
			const centerY = rect.top + rect.height / 2;
			const distance = Math.sqrt(Math.pow(x - centerX, 2) + Math.pow(y - centerY, 2));
			if (distance < minDistance) {
				minDistance = distance;
				closestDiv = div;
			}
		});
		return closestDiv;
	}
	
	function handleMouseDown(event) {
		// Check if the mousedown event happened inside the container
		if (!containerDiv.contains(event.target)) {
			return;
		}
		
		clearSelection(containerDiv);
		let target = event.target;
		// check if clicked target is an inner div, if so, find parent
		if (target.parentNode.parentNode === containerDiv && 
		    target.parentNode.tagName === 'DIV') {
    			target = target.parentNode
		}
		
		
		if (target.parentNode === containerDiv && 
		    target.tagName === 'DIV') {
    			isSelecting = true;
    			startDiv = target;
    			startElement = startDiv
    			handleMouseMove(event); // Initialize on mousedown
		}
	}
	
	
	function handleMouseMove(event) {
		if (!isSelecting) return;
		if (!containerDiv.contains(event.target)) {
			return;
		}
		let currentDiv = getClosestInnerDiv(event.clientX, event.clientY, containerDiv);
		endElement = currentDiv
		clearSelection(containerDiv);
		
		let innerDivs = getInnerDivs(containerDiv);
		const startIndex = innerDivs.indexOf(startDiv);
		const currentIndex = innerDivs.indexOf(currentDiv);
		if (startIndex === -1 || currentIndex === -1) {
			return;
		}
		
		const start = Math.min(startIndex, currentIndex);
		const end = Math.max(startIndex, currentIndex);
		
		// Clear selection of last divs and store currently selected divs
		lastSelectedDivs.forEach(div => {
			div.classList.remove('selected-period');
		});
		lastSelectedDivs = [];
		for (let i = start; i <= end; i++) {
			innerDivs[i].classList.add('selected-period');
			lastSelectedDivs.push(innerDivs[i]);
		}
		startDate = startElement.getAttribute('start-date') < endElement.getAttribute('start-date') ? startElement.getAttribute('start-date') : endElement
			.getAttribute('start-date')
		endDate = startElement.getAttribute('end-date') > endElement.getAttribute('end-date') ? startElement.getAttribute('end-date') : endElement.getAttribute(
			'end-date')
	}
	
	function handleMouseUp(event) {
		if (isSelecting) {
			visApi()
				.setDateFilterSelectedValues(settings.datesFilterId, [new Date(startDate), new Date(endDate)])
			//visApi().setDateFilterSelectedValues(settings.secondDatesFilterId, [new Date(startDate), new Date(endDate)])
		}
		isSelecting = false;
		startDiv = null;
		lastSelectedDivs = [];
	}
	
	
	function handleClick(event) {
		//Check if the click event happened inside the container
		if (!containerDiv.contains(event.target)) {
			return;
		}
		
		clearSelection(containerDiv);
		let target = event.target;
		// check if clicked target is an inner div, if so, find parent
		if (target.parentNode.parentNode === containerDiv && target.parentNode.tagName === 'DIV') {
			target = target.parentNode
		}
		if (target.parentNode === containerDiv && target.tagName === 'DIV') {
			startElement = target
			endElement = target
			startDate = startElement.getAttribute('start-date')
			endDate = startElement.getAttribute('end-date')
			visApi()
				.setDateFilterSelectedValues(settings.datesFilterId, [new Date(startDate), new Date(endDate)])
			//visApi().setDateFilterSelectedValues(settings.secondDatesFilterId, [new Date(startDate), new Date(endDate)])
			target.classList.add('selected-period')
		}
	}
	
	if (containerDiv){
    	containerDiv.addEventListener('mousedown', handleMouseDown);
    	containerDiv.addEventListener('mousemove', handleMouseMove);
    	containerDiv.addEventListener('mouseup', handleMouseUp);
    	containerDiv.addEventListener('click', handleClick);
	}
}

function setColorOfDivs() {
	// Получаем все div-элементы с классом period-block, которые не скрыты
	const periodDivs = datePicker.querySelectorAll('div.period-block:not(.hidden) div');
	// Преобразуем начальную и конечную даты в миллисекунды
	const startDate = Date.parse(dates.startDate);
	const endDate = Date.parse(dates.endDate);
	
	// Флаги для отслеживания начала и конца выбранного периода
	let isStarted = false;
	let isFinished = false;
	
	periodDivs.forEach(div => {
		// Сбрасываем стили и классы
		div.style.background = '';
		div.style.color = '';
		div.classList.remove('selected-period');
		
		// Преобразуем даты div-элемента в миллисекунды
		const divStartDate = Date.parse(div.getAttribute('start-date'));
		const divEndDate = Date.parse(div.getAttribute('end-date'));
		
		// Вычисляем процентное соотношение начала и конца выбранного периода относительно div-элемента
		// Используем Math.max и Math.min для обработки потенциальных ошибок, 
		// когда divStartDate или divEndDate равны startDate или endDate
		let startDiff = 100 * Math.max(0, startDate - divStartDate) / Math.max(1, divEndDate - divStartDate); //избегаем деления на ноль
		let endDiff = 100 * Math.max(0, divEndDate - endDate) / Math.max(1, divEndDate - divStartDate); //избегаем деления на ноль
		
		// Определяем начало и конец выбранного периода
		if (startDiff >= 0 && endDiff <= 0) {
			isStarted = true;
		}
		if (isStarted && endDiff >= 0) {
			isFinished = true;
		}
		
		// Корректируем значения startDiff и endDiff, чтобы они находились в диапазоне от 0 до 100
		startDiff = Math.min(100, Math.max(0, startDiff));
		endDiff = isStarted ? Math.min(100, Math.max(0, 100 - endDiff)) : 100;
		
		
		// Применяем стили, если период выбран
		if (startDiff < 100 && endDiff > 0) {
			div.classList.add('selected-period');
			div.style.background = `linear-gradient(
        90deg,
        ${settings.notSelectedColor} 0%,
        ${settings.notSelectedColor} ${startDiff.toFixed(0)}%,
        ${settings.selectedColor} ${startDiff.toFixed(0)}%,
        ${settings.selectedColor} ${endDiff.toFixed(0)}%,
        ${settings.notSelectedColor} ${endDiff.toFixed(0)}%,
        ${settings.notSelectedColor} 100%
      )`;
			// Устанавливаем белый цвет текста, если выбранный период занимает большую часть div-элемента
			div.style.color = (startDiff < 20 && endDiff > 80) ? '#fff' : '';
		}
	});
}

