    function waitForElement(selector, intervalMs = 100) {
        return new Promise(resolve => {
          const checkElement = setInterval(() => {
            if (document.querySelector(selector)) {
              clearInterval(checkElement);
              resolve(selector);
            }
          }, intervalMs);
        });
      }
    
