        console.warn(`No elements with class 'secondary-filter-value' found within the filterDiv.`);
        return;
      }
    
      const searchInput = filterDiv.querySelector('input');
      // Add event listener for keyup (better for responsiveness than keydown)
      searchInput.addEventListener('keyup', () => {
        const searchTerm = searchInput.value.toLowerCase();
        filterValues.forEach(item => {
          const textContent = item.getAttribute('prev-value').toLowerCase();
          if (textContent.includes(searchTerm)) {
            item.classList.remove('is-hidden-by-search')
          } else {
            item.classList.add('is-hidden-by-search')
          }
        });
      });
    }
    
