        let values = div.querySelectorAll('.secondary-filter-value')
        values.forEach(value => {
            value.innerText = dictObj[value.getAttribute('prev-value')] || value.innerText
        })
    }
    
    function moveSelectedValuesToStart(data, selectedValues) {
        // Iterate over the data array in reverse order
        for (let i = data.length - 1; i >= 0; i--) {
            // Check if the current value is in selectedValues
            if (selectedValues.includes(data[i])) {
                // Remove the value from its current position
                const value = data.splice(i, 1)[0];
                // Add the value to the start of the array
                data.unshift(value);
            }
        }
        return data;
    }
    
    
