    // Function to save a filter state
    function saveFilterState(name) {
        const filterStates = JSON.parse(localStorage.getItem(w.general.renderTo + '-filterStates')) || {};
        filterStates[name] = getFiltersState();
        localStorage.setItem(w.general.renderTo + '-filterStates', JSON.stringify(filterStates));
        updateStatesList();
    }
    
    // Function to load a filter state
    function loadFilterState(name) {
        const filterStates = JSON.parse(localStorage.getItem(w.general.renderTo + '-filterStates')) || {};
        const state = filterStates[name];
        if (state) {
            console.log(`Loading state: ${name}`, state);
            const dateFiltersIds = Object.keys(state.dateFilters);
            const textFiltersIds = Object.keys(state.textFilters);
            
            // Helper function to process with delay
            async function processWithDelay(array, callback) {
                for (let i = 0; i < array.length; i++) {
                    await new Promise(resolve => setTimeout(resolve, 100));
                    callback(array[i], i, array);
                }
            }
            
            // Process date filters with delay
            processWithDelay(dateFiltersIds, id => {
                let obj = state.dateFilters[id];
                let values = [new Date(obj.startDate), new Date(obj.endDate)];
                visApi().setDateFilterSelectedValues(id, values);
            });
            
            // Process text filters with delay
            processWithDelay(textFiltersIds, id => {
                let obj = state.textFilters[id];
                visApi().setFilterSelectedValues(id, obj.map(item => [item]), {});
            });
            
        } else {
            console.error(`State "${name}" not found.`);
        }
    }
    
    // Function to remove a filter state
    function removeFilterState(name) {
        const filterStates = JSON.parse(localStorage.getItem(w.general.renderTo + '-filterStates')) || {};
        if (filterStates[name]) {
            delete filterStates[name];
            localStorage.setItem(w.general.renderTo + '-filterStates', JSON.stringify(filterStates));
            updateStatesList();
        } else {
            console.error(`State "${name}" not found.`);
        }
    }
    
    // Function to update the list of loaded states in the dropdown
    function updateStatesList() {
        const statesList = document.getElementById('states-list');
        const filterStates = JSON.parse(localStorage.getItem(w.general.renderTo + '-filterStates')) || {};
        statesList.innerHTML = '';
    
        for (const [name, state] of Object.entries(filterStates)) {
            const stateRow = document.createElement('div');
            const stateNameSpan = document.createElement('span');
            stateNameSpan.textContent = name;
            stateNameSpan.onclick = () => loadFilterState(name);
    
            const removeButton = document.createElement('button');
            removeButton.textContent = 'X';
            removeButton.onclick = () => removeFilterState(name);
    
            stateRow.appendChild(stateNameSpan);
            stateRow.appendChild(removeButton);
            statesList.appendChild(stateRow);
        }
    }
    
    // Event listener for the "Create filterState" button
    document.getElementById('create-filter-state').addEventListener('click', () => {
        const name = prompt('Enter a name for the new filter state:');
        if (name) {
            saveFilterState(name);
        }
    });
    
    // Initialize the states list on page load
    updateStatesList();
