    function sortVersionStrings(array) {
        return array.sort(compareVersionStrings);
    }
    
    function compareVersionStrings(a, b) {
        if (a === b) return 0;
        if (a === undefined) return -1;
        if (b === undefined) return 1;
        
        // Extract version parts (numbers before the first space)
        const versionA = (a.split(' ')[0] || '').split('.').map(Number);
        const versionB = (b.split(' ')[0] || '').split('.').map(Number);
        
        // Compare each numeric part
        const maxLength = Math.max(versionA.length, versionB.length);
        for (let i = 0; i < maxLength; i++) {
            const numA = versionA[i] || 0;
            const numB = versionB[i] || 0;
            
            if (numA > numB) return 1;
            if (numA < numB) return -1;
        }
        
        // If version parts are equal, compare the rest of the string
        return a.localeCompare(b);
    }
}

