function createWidget(){ 
    // Находим контейнер для виджета фильтров
    let filterDiv = document.querySelector(`#widget-${w.general.renderTo} .secondary-filter-block`); 
    // Находим контейнер для значений фильтров
    let filterValues = filterDiv.querySelector('div.secondary-filter-values') 

    // Перебираем значения фильтра
    filter.values.forEach(value => { 
        // Создаем div для каждого значения
        let div = document.createElement('div'); 
        // Добавляем класс для стилизации
        div.classList.add('secondary-filter-value');     
        // Если значение выбрано или нет выбранных значений, добавляем класс "selected"
        if (selectedValues.length === 0 || selectedValues.includes(value)){ 
            div.classList.add('selected') 
        } 
        // Устанавливаем текст значения
        div.innerHTML = `<p>${value.split('. ')[1]}</p>`; 
        // Устанавливаем подсказку и полное название
        div.setAttribute('title', value.split('. ')[1]) 
        div.setAttribute('full-value', value)

        // Вешаем обработчик клика
        div.addEventListener('click', function () { 
            // Если включен режим множественного выбора
            if (filterDiv.classList.contains('multiple-choice-activated')){ 
                // Переключаем класс "will-be-selected"
                this.classList.toggle('will-be-selected');  
                // Добавляем или удаляем значение из массива selectedValues
                if (this.classList.contains('will-be-selected')) { 
                    willBeSelectedValues.push(this.getAttribute('full-value')); 
                } else { 
                    willBeSelectedValues.splice(willBeSelectedValues.indexOf(this.getAttribute('full-value')), 1); 
                } 
            // Если режим множественного выбора выключен
            } else { 
                // Находим все элементы значений фильтра
                let filterValues = filterDiv.querySelectorAll('.secondary-filter-value') 
                // Проверяем, выбран ли элемент
                let isSelected = false //this.classList.contains('selected') 
                // Если выбран и всего один элемент выбран, очищаем массив selectedValues, иначе устанавливаем выбранное значение
                selectedValues = isSelected && selectedValues.length === 1 ? [] : [this.getAttribute('full-value')] 
                // Обновляем значения фильтра на сервере
                visApi().setFilterSelectedValues(filter.id, selectedValues.length === 0 ? [] : selectedValues.map(x => [x]), function (response) {}); 
            } 
            // Сохраняем выбранные значения в localStorage
            localStorage.setItem('selected_' + filter.name, selectedValues) 
        }); 

        // Добавляем div в контейнер
        filterValues.appendChild(div); 
    }); 

    // Находим элементы управления множественным выбором
    let filterMultipleChoice          = filterDiv.querySelector('.filter-values-multiple-choice') 
    let filterMultipleChoiceActivate  = filterMultipleChoice.querySelector('i.multiple-choice-activate') 
    let filterMultipleChoiceSelectAll = filterMultipleChoice.querySelector('i.multiple-choice-select-all') 
    let filterMultipleChoiceApply     = filterMultipleChoice.querySelector('i.multiple-choice-apply') 

    // Вешаем обработчик на кнопку активации множественного выбора
    filterMultipleChoiceActivate.addEventListener('click', function(){ 
        // Показывает и скрывает элементы управления
        filterMultipleChoiceActivate.style.display = 'none' 
        filterMultipleChoiceSelectAll.style.display = 'block'  
        filterMultipleChoiceApply.style.display = 'block' 
        // Включает режим множественного выбора
        filterDiv.classList.add('multiple-choice-activated') 
        
        willBeSelectedValues = []
        let filterValueDivs = filterDiv.querySelectorAll('div.secondary-filter-value')
        filterValueDivs.forEach(div => {
            if (selectedValues.length === 0 || selectedValues.includes(div.getAttribute('full-value'))){
                div.classList.add('will-be-selected')
                willBeSelectedValues.push(div.getAttribute('full-value'))
            } else {
                div.classList.remove('will-be-selected')
            } 
        })
    }) 

    // Вешаем обработчик на кнопку выбора всех элементов
    filterMultipleChoiceSelectAll.addEventListener('click', function(){ 
        let filterValueDivs = filterDiv.querySelectorAll('div.secondary-filter-value')
        let willBeSelectedDivs = filterDiv.querySelectorAll('div.will-be-selected') 
        // Если все элементы выбраны, снимаем выделение со всех, иначе выделяем все
        if (willBeSelectedDivs.length === filter.values.length){ 
            filterValueDivs.forEach(div => { 
                div.classList.remove('will-be-selected')
            }) 
        } else { 
            filterValueDivs.forEach(div => { 
                div.classList.add('will-be-selected') 
            }) 
        }
        willBeSelectedValues = filter.values
    }) 

    // Вешаем обработчик на кнопку применения множественного выбора
    filterMultipleChoiceApply.addEventListener('click', function(){ 
        // Показывает и скрывает элементы управления
        filterMultipleChoiceActivate.style.display = 'block' 
        filterMultipleChoiceSelectAll.style.display = 'none' 
        filterMultipleChoiceApply.style.display = 'none' 
        // Выключает режим множественного выбора
        filterDiv.classList.remove('multiple-choice-activated') 
        
        if (willBeSelectedValues.length === filter.values.length){
            willBeSelectedValues = []
        }
        // Обновляем значения фильтра на сервере
        visApi().setFilterSelectedValues(filter.id, willBeSelectedValues.length === 0 ? [] : willBeSelectedValues.map(x => [x]), function (response) {}); 
        willBeSelectedValues = []
        updateWidget() 
    }) 
}

function updateWidget(){
    let filterValues = document.querySelectorAll(`#widget-${w.general.renderTo} div.secondary-filter-value`)
    filterValues.forEach(div => {
        ['will-be-selected', 'value-is-filtered'].forEach(className => {
            div.classList.remove(className)
        })
        
        if (selectedValues.length === 0 || selectedValues.includes(div.getAttribute('full-value'))){
            div.classList.add('selected')
        } else {
            div.classList.remove('selected')
        }
    })
    // Сохраняем выбранные значения в localStorage
    localStorage.setItem('selected_' + filter.name, selectedValues) 
}

