function changeDateToStartOfPeriod(date, periodType, toStart) {
    const dateObj = new Date(date);
    let year = dateObj.getFullYear();
    let month = dateObj.getMonth(); // 0-based index
    let day;

    switch (periodType) {
        case 'Месяц':
            if (toStart) {
                day = 1;
            } else {
                day = new Date(year, month + 1, 0).getDate(); // Last day of the month
            }
            break;

        case 'Квартал':
            const quarterStartMonth = Math.floor(month / 3) * 3;
            if (toStart) {
                month = quarterStartMonth;
                day = 1;
            } else {
                month = quarterStartMonth + 2;
                day = new Date(year, month + 1, 0).getDate(); // Last day of the quarter
            }
            break;

        case 'Полугодие':
            const halfYearStartMonth = Math.floor(month / 6) * 6;
            if (toStart) {
                month = halfYearStartMonth;
                day = 1;
            } else {
                month = halfYearStartMonth + 5;
                day = new Date(year, month + 1, 0).getDate(); // Last day of the half year
            }
            break;

        case 'Год':
            if (toStart) {
                month = 0;
                day = 1;
            } else {
                month = 11;
                day = 31;
            }
            break;

        default:
            throw new Error('Invalid periodType');
    }

    // Format the date as 'yyyy-mm-dd'
    const formattedDate = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return formattedDate;
}

