    async function waitForAllWidgetsLoaded(dataWidgetIds) {
      if (isProcessing){
          return
      }
      
      isProcessing = true
      
      if (!dataWidgetIds || dataWidgetIds.length === 0) {
        console.warn("No widget IDs provided.");
        return;
      }
    
      const checkWidgetLoading = (widgetId) => {
        return new Promise((resolve) => {
          const intervalId = setInterval(() => {
            try {
                const widget = visApi().getWidgetByGuid(widgetId);
                if(widget && widget.isLoaded)
                {
                  clearInterval(intervalId);
                  resolve();
                }
            } catch(error) {
                //Handle the case where widget is not found or getWidgetByGuid fails
                console.error(`Error getting widget with ID ${widgetId}:`, error);
                clearInterval(intervalId);
                resolve();// resolve anyway, as the widget does not exsit.
            }
    
          }, 100);
        });
      };
    
    
      // Use Promise.all to wait for all widgets to load.
      try {
        await Promise.all(dataWidgetIds.map(checkWidgetLoading));
        console.log("All widgets loaded.");
        getDataFromWidgetsAndCreateBlock(dataWidgetIds)
        isProcessing = false
      } catch (error) {
        console.error("Error waiting for widgets to load:", error);
      }
    }
    
    /**
     * Asynchronously retrieves data from multiple widgets based on their IDs.
     *
     * @async
     * @function getDataFromWidgetsAndCreateBlock
     * @param {string[]} dataWidgetIds - An array of widget IDs to fetch data from.
     * @returns {Promise<{cols: any[], colTypes: any[], values: any[]}>} A promise that resolves to an object containing the combined data, or an empty data object if an error occurs or no widget IDs are provided.
     * The returned object has the following structure:
     * - `cols`: An array containing unique column names.
     * - `colTypes`: An array containing unique data types for each column.
     * - `values`: An array containing the data values, organized by row.
     */
    async function getDataFromWidgetsAndCreateBlock(dataWidgetIds) {
      if (!dataWidgetIds || dataWidgetIds.length === 0) {
        console.warn("No widget IDs provided.");
        return { values: [] };
      }
    
      try {
        // Process all widgets in parallel
        await Promise.all(dataWidgetIds.map(async (widgetId) => {
          try {
            const widgetData = await visApi().getWidgetDataByGuid(widgetId);
            const data = { values: [] };
    
            if (
              widgetData &&
