    function sortByOrderArray(dataArray, orderArray) {
      if (!Array.isArray(dataArray) || !Array.isArray(orderArray)) {
         throw new Error("Both inputs must be arrays.");
      }
    
    
      return [...dataArray].sort((a, b) => {
        const indexA = orderArray.indexOf(a);
        const indexB = orderArray.indexOf(b);
    
        // Handle cases where elements from dataArray are not found in orderArray:
        if (indexA === -1 && indexB === -1) {
            return 0; // Keep order of unfound elements same
        } else if (indexA === -1) {
            return 1; // Put unfound elements at the end
        } else if (indexB === -1) {
            return -1; // Put unfound elements at the end
        }
    
        return indexA - indexB;
      });
    }
    
