function createTable(data) {
    const table = document.createElement('table');

    // Create the header row
    const headerRow = document.createElement('tr');
    data[0].slice(0, -1).forEach(headerText => {
        const th = document.createElement('th');
        th.textContent = headerText;
        headerRow.appendChild(th);
    });
    table.appendChild(headerRow);

    // Create the data rows
    for (let i = 1; i < data.length; i++) {
        const row = document.createElement('tr');
        const rowData = data[i];
        const url = rowData[rowData.length - 1]; // Get the URL from the last cell

        rowData.slice(0, -1).forEach((cellText, cellIndex) => {
            const td = document.createElement('td');

            if (cellIndex === 1) {
                const link = document.createElement('a');
                link.href = url;
                link.textContent = cellText;
                link.target = '_blank';
                td.appendChild(link);
            } else {
                td.textContent = cellText;
            }

            row.appendChild(td);
        });

        table.appendChild(row);
    }

    return table;
}

// Function to show the second element in the middle of the screen or return it to its original position
function showInCenter(firstElement, secondElement, isShown) {
    // Get references to the divs
    const div1 = document.querySelector(firstElement).closest('#table-div');
    const div2 = document.querySelector(secondElement).closest('.va-widget');

    // Add fade-out animation
    //div1.classList.add('fade-out');
    div2.classList.add('fade-out');

    setTimeout(() => {
        if (isShown) {
            // Move the second element to the center of the screen
            div2.style.position = 'fixed';
            div2.style.top = '25%';
            div2.style.left = '25%';
            div2.style.transform = 'translate(calc(50% - 500px), calc(50%-500px))';
            div2.style.zIndex = '1000'; // Ensure it's on top
            div2.style.width = '1000px'
