        SUMX(bv_f_assets_management_ticket,
            IF(
                bv_f_assets_management_ticket[status_abbr] IN {
                    "Завершено (не оплачено)","Закрыто.","Закрыто","Завершено","Закрыто (оплачено)",
                    "Closed","Выполнено","Отменено","Отклонено","Возвращено", "Ожидает утверждения"},  
                bv_f_assets_management_ticket[workorder_maintenance_cnt], 
                0
            )
        )
    ),SUM(bv_f_assets_management_ticket[workorder_maintenance_cnt]), BLANK())

CALCULATE(
    SUMX(
        bv_f_assets_management_ticket,
        bv_f_assets_management_ticket[workorder_cnt]       
    ),
    FILTER(
        bv_f_assets_management_ticket, 
        OR(
            NOT (bv_f_assets_management_ticket[status_abbr] IN {"Закрыто", "Выполнено"}),
            bv_f_assets_management_ticket[effective_to_dt] >= MAX(bv_f_assets_management_ticket[effective_from_dt])
        )
    )
)

